#include<bits/stdc++.h>
using namespace std;
double f[9][9][9][9][15],X;
double s[9][9];
int n;
double calc(int ax,int ay,int bx,int by)
{
    double sum=s[bx][by]-s[ax-1][by]-s[bx][ay-1]+s[ax-1][ay-1]-X;
    return sum*sum/n;
}
double dp(int ax,int ay,int bx,int by,int k)
{
    if(f[ax][ay][bx][by][k]>=0)
    {
        return f[ax][ay][bx][by][k];
    }
    if(k==1)
    {
        return calc(ax,ay,bx,by);
    }
    f[ax][ay][bx][by][k]=1e9;
    for(int i=ax;i<bx;i++)
    {
        f[ax][ay][bx][by][k]=min({f[ax][ay][bx][by][k],dp(ax,ay,i,by,k-1)+calc(i+1,ay,bx,by),calc(ax,ay,i,by)+dp(i+1,ay,bx,by,k-1)});
    }
    for(int i=ay;i<by;i++)
    {
        f[ax][ay][bx][by][k]=min({f[ax][ay][bx][by][k],dp(ax,ay,bx,i,k-1)+calc(ax,i+1,bx,by),calc(ax,ay,bx,i)+dp(ax,i+1,bx,by,k-1)});
    }
    return f[ax][ay][bx][by][k];
}
int main()
{
    for(int i=1;i<=8;i++)
    {
        for(int j=1;j<=8;j++)
        {
            for(int k=1;k<=8;k++)
            {
                for(int l=1;l<=8;l++)
                {
                    for(int o=1;o<=14;o++)
                    {
                        f[i][j][k][l][o]=-1;
                    }
                }
            }
        }
    }
    scanf("%d",&n);
    for(int i=1;i<=8;i++)
    {
        for(int j=1;j<=8;j++)
        {
            scanf("%lf",&s[i][j]);
            s[i][j]+=s[i-1][j]+s[i][j-1]-s[i-1][j-1];
        }
    }
    X=s[8][8]/n;
    printf("%.3lf",sqrt(dp(1,1,8,8,n)));
    return 0;
}
